import React, { useState, useEffect } from 'react';
import api from '../api/axios';

export default function AddEndpointModal({ onClose, onAdded }) {
  const [form, setForm]       = useState({ name: '', url: '', checkIntervalSeconds: 60 });
  const [error, setError]     = useState('');
  const [visible, setVisible] = useState(false);
  const [loading, setLoading] = useState(false);

  useEffect(() => { requestAnimationFrame(() => setVisible(true)); }, []);

  const handle = e => setForm({ ...form, [e.target.name]: e.target.value });
  const handleClose = () => { setVisible(false); setTimeout(onClose, 200); };

  const submit = async e => {
    e.preventDefault();
    setLoading(true);
    try {
      const { data } = await api.post('/api/endpoints', { ...form, checkIntervalSeconds: Number(form.checkIntervalSeconds) });
      onAdded(data);
      handleClose();
    } catch {
      setError('Failed to add endpoint');
      setLoading(false);
    }
  };

  const intervals = [
    { value: 30,  label: '30s' },
    { value: 60,  label: '1m'  },
    { value: 300, label: '5m'  },
    { value: 600, label: '10m' },
  ];

  const inputCls = "w-full px-3.5 py-2.5 text-sm rounded-xl bg-[#e5e7eb] dark:bg-gh-canvas border border-transparent focus:border-brand-blue focus:outline-none focus:ring-2 focus:ring-brand-blue/20 text-gray-800 dark:text-gh-text placeholder-gray-400 dark:placeholder-gh-dim transition-all";

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 dark:bg-black/60 backdrop-blur-sm transition-opacity"
      style={{ opacity: visible ? 1 : 0 }}
      onClick={handleClose}
    >
      <div
        className="w-full max-w-md bg-white dark:bg-gh-default rounded-2xl shadow-xl dark:shadow-none dark:border dark:border-gh-border overflow-hidden transition-all"
        style={{ transform: visible ? 'translateY(0) scale(1)' : 'translateY(-8px) scale(0.98)', opacity: visible ? 1 : 0 }}
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-start justify-between px-5 py-4 border-b border-gray-100 dark:border-gh-border">
          <div>
            <h2 className="text-base font-semibold text-gray-900 dark:text-gh-text">Add endpoint</h2>
            <p className="text-sm text-gray-500 dark:text-gh-muted mt-0.5">Monitor a new API endpoint</p>
          </div>
          <button onClick={handleClose} className="text-gray-400 hover:text-gray-700 dark:hover:text-gh-text text-lg leading-none mt-0.5 transition-colors">✕</button>
        </div>

        {error && (
          <div className="mx-5 mt-4 flex items-center gap-2 px-3 py-2.5 bg-red-50 dark:bg-transparent text-red-600 dark:text-red-400 border border-red-200 dark:border-red-400/30 rounded-xl text-sm">
            <span>⚠</span> {error}
          </div>
        )}

        <form onSubmit={submit} className="p-5 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gh-muted mb-1.5">Name</label>
            <input className={inputCls} name="name" placeholder="e.g. Auth API" onChange={handle} required autoFocus />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gh-muted mb-1.5">URL</label>
            <input className={inputCls} name="url" type="url" placeholder="https://api.example.com/health" onChange={handle} required />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gh-muted mb-2">Check interval</label>
            <div className="flex gap-2">
              {intervals.map(({ value, label }) => {
                const active = Number(form.checkIntervalSeconds) === value;
                return (
                  <button
                    key={value}
                    type="button"
                    onClick={() => setForm({ ...form, checkIntervalSeconds: value })}
                    className={`flex-1 py-2 text-xs font-semibold rounded-xl transition-colors border ${
                      active
                        ? 'bg-brand-blue text-white border-brand-blue dark:bg-gh-green dark:border-gh-green'
                        : 'bg-gray-100 dark:bg-gh-canvas text-gray-600 dark:text-gh-muted border-gray-200 dark:border-gh-border hover:bg-gray-200 dark:hover:bg-gh-subtle'
                    }`}
                  >{label}</button>
                );
              })}
            </div>
          </div>

          <div className="flex justify-end gap-3 pt-2 border-t border-gray-100 dark:border-gh-border mt-2">
            <button type="button" onClick={handleClose} className="px-4 py-2 text-sm font-medium text-gray-600 dark:text-gh-muted hover:text-gray-900 dark:hover:text-gh-text rounded-xl hover:bg-gray-100 dark:hover:bg-gh-subtle transition-colors">
              Cancel
            </button>
            <button
              type="submit" disabled={loading}
              className="px-5 py-2 text-sm font-semibold text-white bg-brand-blue hover:bg-brand-blue-h dark:bg-gh-green dark:hover:bg-gh-green-h rounded-xl transition-colors flex items-center gap-2"
            >
              {loading
                ? <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full" style={{ animation: 'spin 0.6s linear infinite' }} />
                : 'Add endpoint'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
